// Node.js/Express backend for 3D Secure 2.0 integration
const express = require('express');
const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);
const crypto = require('crypto');
const redis = require('redis');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

const redisClient = redis.createClient({
  host: 'localhost',
  port: 6379
});

class ThreeDSecureHandler {
  constructor(stripeClient) {
    this.stripe = stripeClient;
    this.riskThreshold = 0.65; // Trigger 3DS for risk >= 65%
  }

  /**
   * Create payment intent with 3DS enforcement based on risk
   */
  async createPaymentIntent(transaction) {
    const idempotencyKey = uuidv4();

    // Determine if 3DS is required based on risk score
    const riskScore = transaction.riskScore || 0.3;
    const requireThreeDS = riskScore >= this.riskThreshold;

    const intentParams = {
      amount: Math.round(transaction.amount * 100), // Convert to cents
      currency: transaction.currency || 'usd',
      payment_method: transaction.paymentMethodId,
      confirm: false,
      return_url: `${process.env.APP_URL}/payment/return`,
      metadata: {
        customerId: transaction.customerId,
        orderId: transaction.orderId,
        riskScore: riskScore.toString(),
        ipAddress: transaction.ipAddress,
        deviceId: transaction.deviceId
      }
    };

    // Enforce 3DS2 for high-risk transactions
    if (requireThreeDS) {
      intentParams.payment_method_options = {
        card: {
          request_three_d_secure: 'require' // Always require 3DS
        }
      };
    } else {
      intentParams.payment_method_options = {
        card: {
          request_three_d_secure: 'automatic' // Use risk-based 3DS
        }
      };
    }

    try {
      const paymentIntent = await this.stripe.paymentIntents.create(
        intentParams,
        { idempotencyKey } // Ensure idempotency
      );

      return {
        clientSecret: paymentIntent.client_secret,
        requiresAction: paymentIntent.status === 'requires_action',
        requiresConfirmation: paymentIntent.status === 'requires_confirmation',
        nextAction: paymentIntent.next_action
      };
    } catch (error) {
      console.error('Payment intent creation failed:', error);
      throw new Error(`3DS setup failed: ${error.message}`);
    }
  }

  /**
   * Confirm payment after 3DS authentication
   */
  async confirmPayment(paymentIntentId, paymentMethodId) {
    try {
      const paymentIntent = await this.stripe.paymentIntents.confirm(
        paymentIntentId,
        {
          payment_method: paymentMethodId
        }
      );

      // Check if 3DS authentication succeeded
      if (paymentIntent.charges.data[0].three_d_secure) {
        const threeDSecure = paymentIntent.charges.data[0].three_d_secure;
        return {
          success: paymentIntent.status === 'succeeded',
          authenticated: threeDSecure.authenticated,
          version: threeDSecure.version,
          threeDSecureId: paymentIntent.id
        };
      }

      return {
        success: paymentIntent.status === 'succeeded',
        authenticated: false
      };
    } catch (error) {
      console.error('Payment confirmation failed:', error);
      throw new Error(`Payment confirmation failed: ${error.message}`);
    }
  }
}

class BehavioralBiometricsHandler {
  constructor(redisClient) {
    this.redis = redisClient;
  }

  /**
   * Generate device fingerprint using behavioral patterns
   */
  generateDeviceFingerprint(userAgent, ipAddress, canvas, webgl) {
    const fingerprintData = {
      userAgent: userAgent,
      ipAddress: ipAddress,
      canvasHash: this.hashCanvas(canvas),
      webglHash: this.hashWebGL(webgl),
      timestamp: Date.now()
    };

    // Create fingerprint hash
    const fingerprint = crypto
      .createHash('sha256')
      .update(JSON.stringify(fingerprintData))
      .digest('hex');

    return fingerprint;
  }

  hashCanvas(canvasData) {
    if (!canvasData) return 'no_canvas';
    return crypto
      .createHash('sha256')
      .update(canvasData)
      .digest('hex')
      .substring(0, 16);
  }

  hashWebGL(webglData) {
    if (!webglData) return 'no_webgl';
    return crypto
      .createHash('sha256')
      .update(webglData)
      .digest('hex')
      .substring(0, 16);
  }

  /**
   * Analyze user behavior patterns for anomalies
   */
  async analyzeBehavior(customerId, deviceFingerprint, behaviorMetrics) {
    const key = `behavior:${customerId}`;

    // Get historical behavior
    const historicalData = await this.redis.get(key);
    let historicalPatterns = [];
    if (historicalData) {
      historicalPatterns = JSON.parse(historicalData);
    }

    // Add current behavior
    historicalPatterns.push({
      deviceFingerprint: deviceFingerprint,
      mouseMovements: behaviorMetrics.mouseMovements,
      typingPattern: behaviorMetrics.typingPattern,
      scrollBehavior: behaviorMetrics.scrollBehavior,
      clickPatterns: behaviorMetrics.clickPatterns,
      timeOnPage: behaviorMetrics.timeOnPage,
      timestamp: Date.now()
    });

    // Keep last 20 sessions
    if (historicalPatterns.length > 20) {
      historicalPatterns = historicalPatterns.slice(-20);
    }

    // Store updated behavior
    await this.redis.setex(
      key,
      86400 * 30, // 30 days TTL
      JSON.stringify(historicalPatterns)
    );

    // Detect anomalies
    const anomalyScore = this.calculateAnomalyScore(
      behaviorMetrics,
      historicalPatterns
    );

    return {
      anomalyScore: anomalyScore,
      isAnomaly: anomalyScore > 0.7,
      deviceFingerprint: deviceFingerprint
    };
  }

  calculateAnomalyScore(currentBehavior, historicalPatterns) {
    if (historicalPatterns.length < 3) {
      return 0.2; // Low confidence with few historical patterns
    }

    // Calculate deviations from historical patterns
    let totalDeviation = 0;
    const metrics = [
      'mouseMovements',
      'typingPattern',
      'scrollBehavior',
      'clickPatterns',
      'timeOnPage'
    ];

    for (const metric of metrics) {
      const historicalValues = historicalPatterns.map(p => p[metric] || 0);
      const average = historicalValues.reduce((a, b) => a + b, 0) / historicalValues.length;
      const stdDev = Math.sqrt(
        historicalValues.reduce((sq, n) => sq + Math.pow(n - average, 2), 0) / historicalValues.length
      );

      // Calculate z-score
      const zScore = stdDev === 0 ? 0 : Math.abs((currentBehavior[metric] - average) / stdDev);
      totalDeviation += Math.min(zScore / 3, 1); // Normalize to 0-1
    }

    // Average deviation across all metrics
    return Math.min(totalDeviation / metrics.length, 1.0);
  }
}

class MultiFactorAuthHandler {
  constructor(redisClient) {
    this.redis = redisClient;
  }

  /**
   * Send OTP via SMS for high-risk transactions
   */
  async sendSMSOTP(phoneNumber, customerId) {
    const otp = Math.random().toString().slice(2, 8); // 6-digit OTP
    const key = `otp:${customerId}`;

    // Store OTP with 5-minute expiration
    await this.redis.setex(key, 300, otp);

    // In production, use Twilio or AWS SNS
    console.log(`Sending OTP ${otp} to ${phoneNumber}`);

    // Simulate SMS send
    return {
      success: true,
      expiresIn: 300, // 5 minutes
      maskedPhone: phoneNumber.slice(-4)
    };
  }

  /**
   * Verify OTP submitted by user
   */
  async verifyOTP(customerId, submittedOTP) {
    const key = `otp:${customerId}`;
    const storedOTP = await this.redis.get(key);

    if (!storedOTP) {
      return {
        valid: false,
        error: 'OTP expired or not found'
      };
    }

    // Constant-time comparison to prevent timing attacks
    const isValid = crypto.timingSafeEqual(
      Buffer.from(submittedOTP),
      Buffer.from(storedOTP)
    );

    if (isValid) {
      // Delete OTP after successful verification
      await this.redis.del(key);
    }

    return {
      valid: isValid,
      error: isValid ? null : 'Invalid OTP'
    };
  }

  /**
   * Generate TOTP (Time-based OTP) for authenticator apps
   */
  generateTOTPSecret(customerId) {
    const secret = crypto.randomBytes(32).toString('base64');
    const key = `totp:${customerId}`;

    // Store TOTP secret securely
    this.redis.setex(key, 86400 * 365, secret); // 1 year

    // Generate QR code URL for authenticator app
    const otpauthUrl = `otpauth://totp/PaymentApp:${customerId}?secret=${secret}&issuer=PaymentApp`;

    return {
      secret: secret,
      qrCodeUrl: otpauthUrl,
      backupCodes: this.generateBackupCodes(5)
    };
  }

  generateBackupCodes(count) {
    const codes = [];
    for (let i = 0; i < count; i++) {
      codes.push(crypto.randomBytes(4).toString('hex'));
    }
    return codes;
  }
}

// Express routes
const threeDSecureHandler = new ThreeDSecureHandler(stripe);
const biometricsHandler = new BehavioralBiometricsHandler(redisClient);
const mfaHandler = new MultiFactorAuthHandler(redisClient);

/**
 * Endpoint: Create payment with risk-based 3DS
 */
app.post('/api/payments/create', async (req, res) => {
  try {
    const transaction = req.body;

    // Create payment intent with risk-based 3DS
    const payment = await threeDSecureHandler.createPaymentIntent(transaction);

    // If high risk, also require OTP
    if (transaction.riskScore >= 0.65) {
      const mfa = await mfaHandler.sendSMSOTP(
        transaction.phoneNumber,
        transaction.customerId
      );
      payment.mfaRequired = true;
      payment.mfaMethod = 'sms'
    }

    res.json(payment);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

/**
 * Endpoint: Confirm payment after 3DS and MFA
 */
app.post('/api/payments/confirm', async (req, res) => {
  try {
    const { paymentIntentId, paymentMethodId, otp } = req.body;

    // Verify OTP if provided
    if (otp) {
      const otpResult = await mfaHandler.verifyOTP(
        req.body.customerId,
        otp
      );
      if (!otpResult.valid) {
        return res.status(400).json({ error: otpResult.error });
      }
    }

    // Confirm payment
    const result = await threeDSecureHandler.confirmPayment(
      paymentIntentId,
      paymentMethodId
    );

    res.json(result);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

/**
 * Endpoint: Analyze behavioral biometrics
 */
app.post('/api/biometrics/analyze', async (req, res) => {
  try {
    const { customerId, userAgent, ipAddress, canvas, webgl, behaviors } = req.body;

    // Generate device fingerprint
    const fingerprint = biometricsHandler.generateDeviceFingerprint(
      userAgent,
      ipAddress,
      canvas,
      webgl
    );

    // Analyze behavior for anomalies
    const analysis = await biometricsHandler.analyzeBehavior(
      customerId,
      fingerprint,
      behaviors
    );

    res.json(analysis);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

/**
 * Client-side JavaScript for behavioral biometrics collection
 */
const clientSideScript = `
// Collect behavioral biometrics on payment form
class BehavioralBiometricsCollector {
  constructor() {
    this.metrics = {
      mouseMovements: 0,
      typingPattern: [],
      scrollBehavior: 0,
      clickPatterns: [],
      timeOnPage: 0
    };
    this.startTime = Date.now();
    this.setupEventListeners();
  }

  setupEventListeners() {
    // Track mouse movements
    document.addEventListener('mousemove', (e) => {
      this.metrics.mouseMovements += 1;
    });

    // Track typing patterns (keystroke dynamics)
    document.addEventListener('keypress', (e) => {
      this.metrics.typingPattern.push(Date.now());
    });

    // Track scroll behavior
    window.addEventListener('scroll', (e) => {
      this.metrics.scrollBehavior += 1;
    });

    // Track click patterns
    document.addEventListener('click', (e) => {
      this.metrics.clickPatterns.push({
        x: e.clientX,
        y: e.clientY,
        timestamp: Date.now()
      });
    });
  }

  getMetrics() {
    this.metrics.timeOnPage = (Date.now() - this.startTime) / 1000;
    return this.metrics;
  }

  getCanvasFingerprint() {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    ctx.textBaseline = 'top';
    ctx.font = '14px Arial';
    ctx.fillText('Canvas Fingerprint', 2, 2);
    return canvas.toDataURL();
  }

  getWebGLFingerprint() {
    const canvas = document.createElement('canvas');
    const gl = canvas.getContext('webgl');
    return gl.getParameter(gl.RENDERER);
  }
}

const collector = new BehavioralBiometricsCollector();

// Send biometrics to server
function submitPayment() {
  const metrics = collector.getMetrics();
  const canvas = collector.getCanvasFingerprint();
  const webgl = collector.getWebGLFingerprint();

  fetch('/api/biometrics/analyze', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      customerId: document.getElementById('customerId').value,
      userAgent: navigator.userAgent,
      ipAddress: document.getElementById('ipAddress').value,
      canvas: canvas,
      webgl: webgl,
      behaviors: metrics
    })
  });
}
`;

